COPY public.raw_texts (id, source_id, book_id, volume, chapter, paragraph_no, raw_text, text_original, variant_of_id, text_version, created_at, updated_at, deleted_at) FROM stdin;
07ef840c-2050-46c9-8f00-d658fb575e69	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	1	黄帝者，少典之子，姓公孙，名曰轩辕。生而神灵，弱而能言，幼而徇齐，长而敦敏，成而聪明。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
d0fbae50-d617-4902-abd1-d702647dd7e2	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	2	轩辕之时，神农氏世衰。诸侯相侵伐，暴虐百姓，而神农氏弗能征。于是轩辕乃习用干戈，以征不享，诸侯咸来宾从。而蚩尤最为暴，莫能伐。炎帝欲侵陵诸侯，诸侯咸归轩辕。轩辕乃修德振兵，治五气，艺五种，抚万民，度四方，教熊罴貔貅貙虎，以与炎帝战于阪泉之野。三战然后得其志。蚩尤作乱，不用帝命。于是黄帝乃徵师诸侯，与蚩尤战于涿鹿之野，遂禽杀蚩尤。而诸侯咸尊轩辕为天子，代神农氏，是为黄帝。天下有不顺者，黄帝从而征之，平者去之，披山通道，未尝宁居。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
f967b7b6-5755-43c5-8b6a-ab02c834daf6	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	3	东至于海，登丸山，及岱宗。西至于空桐，登鸡头。南至于江，登熊、湘。北逐荤粥，合符釜山，而邑于涿鹿之阿。迁徙往来无常处，以师兵为营卫。官名皆以云命，为云师。置左右大监，监于万国。万国和，而鬼神山川封禅与为多焉。获宝鼎，迎日推厕。举风后、力牧、常先、大鸿以治民。顺天地之纪，幽明之占，死生之说，存亡之难。时播百谷草木，淳化鸟兽虫蛾，旁罗日月星辰水波土石金玉，劳勤心力耳目，节用水火材物。有土德之瑞，故号黄帝。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
c92a751e-5ed5-400f-999d-6f6cbac67c7f	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	4	黄帝二十五子，其得姓者十四人。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
556174bb-673e-4e23-9b85-c47e5d6a3d13	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	5	黄帝居于轩辕之丘，而娶于西陵之女，是为嫘祖为黄帝正妃，生二子，其后皆有天下：其一曰玄嚣，是为青阳，青阳降居江水；其二曰昌意，降居若水。昌意娶蜀山氏女，曰昌仆，生高阳，高阳有圣德焉。黄帝崩，葬桥山。其孙昌意之子高阳立，是为帝颛顼也。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
d655331c-c6b7-4cac-8838-4fbc8f420cf0	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	6	帝颛顼高阳者，黄帝之孙而昌意之子也。静渊以有谋，疏通而知事；养材以任地，载时以象天，依鬼神以制义，治气以教化，洁诚以祭祀。北至于幽陵，南至于交址，西至于流沙，东至于蟠木。动静之物，大小之神，日月所照，莫不砥属。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
8c2da789-17ed-45ab-970e-1c738f79f73c	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	7	帝颛顼生子曰穷蝉。颛顼崩，而玄嚣之孙高辛立，是为帝喾。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
7cd7fb6c-8c81-49c2-bba9-e49b7d7e7341	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	8	帝喾高辛者，黄帝之曾孙也。高辛父曰蟜极，蟜极父曰玄嚣，玄嚣父曰黄帝。自玄嚣与蟜极皆不得在位，至高辛即帝位。高辛于颛顼为族子。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
7e172002-58eb-416b-baf4-2cfafd2b0446	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	9	高辛生而神灵，自言其名。普施利物，不于其身。聪以知远，明以察微。顺天之义，知民之急。仁而威，惠而信，修身而天下服。取地之财而节用之，抚教万民而利诲之，历日月而迎送之，明鬼神而敬事之。其色郁郁，其德嶷嶷。其动也时，其服也士。帝喾溉执中而遍天下，日月所照，风雨所至，莫不从服。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
cdc8c112-4d89-414d-b20c-5fc806502114	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	10	帝喾娶陈锋氏女，生放勋。娶娵訾氏女，生挚。帝喾崩，而挚代立。帝挚立，不善（崩），而弟放勋立，是为帝尧。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
027fb873-6dd4-4beb-887c-ee048bc9f49f	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	11	帝尧者，放勋。其仁如天，其知如神。就之如日，望之如云。富而不骄，贵而不舒。黄收纯衣，彤车乘白马。能明驯德，以亲九族。九族既睦，便章百姓。百姓昭明，合和万国。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
16052a21-a942-4fc7-9ab7-93a3186ff841	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	12	乃命羲、和，敬顺昊天，数法日月星辰，敬授民时。分命羲仲，居郁夷，曰旸谷。敬道日出，便程东作。日中，星鸟，以殷中春。其民析，鸟兽字微。申命羲叔，居南交。便程南为，敬致。日永，星火，以正中夏。其民因，鸟兽希革。申命和仲，居西土，曰昧谷。敬道日入，便程西成。夜中，星虚，以正中秋。其民夷易，鸟兽毛毨。申命和叔；居北方，曰幽都。便在伏物。日短，星昴，以正中冬。其民燠，鸟兽氄毛。岁三百六十六日，以闰月正四时。信饬百官，众功皆兴。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
fa3d7641-623b-4bee-9edb-2884f2c4c23a	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	13	尧曰："谁可顺此事？"放齐曰："嗣子丹朱开明。"尧曰："吁！顽凶，不用。"尧又曰："谁可者？"欢兜曰："共工旁聚布功，可用。"尧曰："共工善言，其用僻，似恭漫天，不可。"尧又曰："嗟，四岳，汤汤洪水滔天，浩浩怀山襄陵，下民其忧，有能使治者？"皆曰鲧可。尧曰："鲧负命毁族，不可。"岳曰："异哉，试不可用而已。"尧于是听岳用鲧。九岁，功用不成。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
ba354c57-dc32-4b5e-a831-67c0e23f8127	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	14	尧曰："嗟！四岳：朕在位七十载，汝能庸命，践朕位？"岳应曰："鄙德忝帝位。"尧曰："悉举贵戚及疏远隐匿者。"众皆言于尧曰："有矜在民闲，曰虞舜。"尧曰："然，朕闻之。其何如？"岳曰："盲者子。父顽，母嚚，弟傲，能和以孝，烝烝治，不至奸。"尧曰："吾其试哉。"于是尧妻之二女，观其德于二女。舜饬下二女于妫汭，如妇礼。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
a872be43-6148-4d03-9f39-277c45fb30b6	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	15	尧善之，乃使舜慎和五典，五典能从。乃遍入百官，百官时序。宾于四门，四门穆穆，诸侯远方宾客皆敬。尧使舜入山林川泽，暴风雷雨，舜行不迷。尧以为圣，召舜曰："女谋事至而言可绩，三年矣。女登帝位。"舜让于德不怿。正月上日，舜受终于文祖。文祖者，尧大祖也。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
76891617-b73d-42f0-b108-a696dc2f27c4	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	16	于是帝尧老，命舜摄行天子之政，以观天命。舜乃在璇玑玉衡，以齐七政。遂类于上帝，禋于六宗，望于山川，辩于群神。揖五瑞，择吉月日，见四岳诸牧，班瑞。岁二月，东巡狩，至于岱宗，祡，望秩于山川。遂见东方君长，合时月正日，同律度量衡，修五礼五玉三帛二生一死为挚，如五器，卒乃复。五月，南巡狩；八月，西巡狩；十一月，北巡狩：皆如初。归，至于祖祢庙，用特牛礼。五岁一巡狩，群后四朝。遍告以言，明试以功，车服以庸。肇十有二州，决川。象以典刑，流宥五刑，鞭作官刑，扑作教刑，金作赎刑。眚灾过，赦；怙终贼，刑。钦哉，钦哉，惟刑之静哉！	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
a06c5c94-6a12-4775-b946-83f7a9f91800	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	17	欢兜进言共工，尧曰不可而试之工师，共工果淫辟。四岳举鲧治鸿水，尧以为不可，岳强请试之，试之而无功，故百姓不便。三苗在江淮、荆州数为乱。于是舜归而言于帝，请流共工于幽陵，以变北狄；放欢兜于崇山，以变南蛮；迁三苗于三危，以变西戎；殛鲧于羽山，以变东夷：四罪而天下咸服。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
48797e41-0867-4410-bf8e-84c46d92f4fa	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	18	尧立七十年得舜，二十年而老，令舜摄行天子之政，荐之于天。尧辟位凡二十八年而崩。百姓悲哀，如丧父母。三年，四方莫举乐，以思尧。尧知子丹朱之不肖，不足授天下，于是乃权授舜。授舜，则天下得其利而丹朱病；授丹朱，则天下病而丹朱得其利。尧曰："终不以天下之病而利一人"，而卒授舜以天下。尧崩，三年之丧毕，舜让辟丹朱于南河之南。诸侯朝觐者不之丹朱而之舜，狱讼者不之丹朱而之舜，讴歌者不讴歌丹朱而讴歌舜。舜曰："天也"，夫而后之中国践天子位焉，是为帝舜。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
1105bd27-e798-4c73-aa12-d38af0e57aab	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	19	虞舜者，名曰重华。重华父曰瞽叟，瞽叟父曰桥牛，桥牛父曰句望，句望父曰敬康，敬康父曰穷蝉，穷蝉父曰帝颛顼，颛顼父曰昌意：以至舜七世矣。自从穷蝉以至帝舜，皆微为庶人。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
c35994ac-bb6e-475c-9959-8f7c36ef8b25	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	20	舜父瞽叟盲，而舜母死，瞽叟更娶妻而生象，象傲。瞽叟爱后妻子，常欲杀舜，舜避逃；及有小过，则受罪。顺事父及后母与弟，日以笃谨，匪有解。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
ac6b0281-d62c-439b-b52b-e87f021f3ed6	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	21	舜，冀州之人也。舜耕历山，渔雷泽，陶河滨，作什器于寿丘，就时于负夏。舜父瞽叟顽，母嚚，弟象傲，皆欲杀舜。舜顺适不失子道，兄弟孝慈。欲杀，不可得；即求，尝在侧。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
b9c3b154-4194-4269-9202-e7df8acb7539	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	22	舜年二十以孝闻。三十而帝尧问可用者，四岳咸荐虞舜，曰可。于是尧乃以二女妻舜以观其内，使九男与处以观其外。舜居妫汭，内行弥谨。尧二女不敢以贵骄事舜亲戚，甚有妇道。尧九男皆益笃。舜耕历山，历山之人皆让畔；渔雷泽，雷泽上人皆让居；陶河滨，河滨器皆不苦窳。一年而所居成聚，二年成邑，三年成都。尧乃赐舜絺衣，与琴，为筑仓廪，予牛羊。瞽叟尚复欲杀之，使舜上涂廪，瞽叟从下纵火焚廪。舜乃以两笠自捍而下，去，得不死。后瞽叟又使舜穿井，舜穿井为匿空旁出。舜既入深，瞽叟与象共下土实井，舜从匿空出，去。瞽叟、象喜，以舜为已死。象曰："本谋者象。"象与其父母分，于是曰："舜妻尧二女，与琴，象取之。牛羊仓廪予父母。"象乃止舜宫居，鼓其琴。舜往见之。象鄂不怿，曰："我思舜正郁陶！"舜曰："然，尔其庶矣！"舜复事瞽叟爱弟弥谨。于是尧乃试舜五典百官，皆治。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
eb6ae154-42ac-4675-9657-519fa524fee9	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	23	昔高阳氏有才子八人，世得其利，谓之"八恺"。高辛氏有才子八人，世谓之"八元"。此十六族者，世济其美，不陨其名。至于尧，尧未能举。舜举八恺，使主后土，以揆百事，莫不时序。举八元，使布五教于四方，父义，母慈，兄友，弟恭，子孝，内平外成。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
7383cda7-3187-4302-a2d8-28d8d20689a3	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	24	昔帝鸿氏有不才子，掩义隐贼，好行凶慝，天下谓之浑沌。少暤氏有不才子，毁信恶忠，崇饰恶言，天下谓之穷奇。颛顼氏有不才子，不可教训，不知话言，天下谓之梼杌。此三族世忧之。至于尧，尧未能去。缙云氏有不才子，贪于饮食，冒于货贿，天下谓之饕餮。天下恶之，比之三凶。舜宾于四门，乃流四凶族，迁于四裔，以御螭魅，于是四门辟，言毋凶人也。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
e441b60e-69f7-4cca-8a51-5b1ac0bf0a95	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	25	舜入于大麓，烈风雷雨不迷，尧乃知舜之足授天下。尧老，使舜摄行天子政，巡狩。舜得举用事二十年，而尧使摄政。摄政八年而尧崩。三年丧毕，让丹朱，天下归舜。而禹、皋陶、契、后稷、伯夷、夔、龙、倕、益、彭祖自尧时而皆举用，未有分职。于是舜乃至于文祖，谋于四岳，辟四门，明通四方耳目，命十二牧论帝德，行厚德，远佞人，则蛮夷率服。舜谓四岳曰："有能奋庸美尧之事者，使居官相事？"皆曰："伯禹为司空，可美帝功。"舜曰："嗟，然！禹，汝平水土，维是勉哉。"禹拜稽首，让于稷、契与皋陶。舜曰："然，往矣。"舜曰："弃，黎民始饥，汝后稷播时百谷。"舜曰："契，百姓不亲，五品不驯，汝为司徒，而敬敷五教，在宽。"舜曰："皋陶，蛮夷猾夏，寇贼奸轨，汝作士，五刑有服，五服三就；五流有度，五度三居：维明能信。"舜曰："谁能驯予工？"皆曰垂可。于是以垂为共工。舜曰："谁能驯予上下草木鸟兽？"皆曰益可。于是以益为朕虞。益拜稽首，让于诸臣朱虎、熊罴。舜曰："往矣，汝谐。"遂以朱虎、熊罴为佐。舜曰："嗟！四岳，有能典朕三礼？"皆曰伯夷可。舜曰："嗟！伯夷，以汝为秩宗，夙夜维敬，直哉维静洁。"伯夷让夔、龙。舜曰："然。以夔为典乐，教稚子，直而温，宽而栗，刚而毋虐，简而毋傲；诗言意，歌长言，声依永，律和声，八音能谐，毋相夺伦，神人以和。"夔曰："于！予击石拊石，百兽率舞。"舜曰："龙，朕畏忌谗说殄伪，振惊朕众，命汝为纳言，夙夜出入朕命，惟信。"舜曰："嗟！女二十有二人，敬哉，惟时相天事。"三岁一考功，三考绌陟，远近众功咸兴。分北三苗。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
7abe6111-9ba8-4800-bbf1-c559664ecd61	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	26	此二十二人咸成厥功：皋陶为大理，平，民各伏得其实；伯夷主礼，上下咸让；垂主工师，百工致功；益主虞，山泽辟；弃主稷，百谷时茂；契主司徒，百姓亲和；龙主宾客，远人至；十二牧行而九州莫敢辟违；唯禹之功为大，披九山，通九泽，决九河，定九州，各以其职来贡，不失厥宜。方五千里，至于荒服。南抚交址、北发，西戎、析枝、渠廋、氐、羌，北山戎、发、息慎，东长、鸟夷，四海之内咸戴帝舜之功。于是禹乃兴九招之乐，致异物，凤皇来翔。天下明德皆自虞帝始。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
ad597b62-7ec0-42d3-a5d9-ef1ee52d6b63	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	15	道九山：汧及岐至于荆山，逾于河；壶口、雷首至于太岳；砥柱、析城至于王屋；太行、常山至于碣石，入于海；西倾、朱圉、鸟鼠至于太华；熊耳、外方、桐柏至于负尾；道嶓冢，至于荆山；内方至于大别；汶山之阳至衡山，过九江，至于敷浅原。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
8276a7de-a502-4974-9841-df91ba3d10f3	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	27	舜年二十以孝闻，年三十尧举之，年五十摄行天子事，年五十八尧崩，年六十一代尧践帝位。践帝位三十九年，南巡狩，崩于苍梧之野。葬于江南九疑，是为零陵。舜之践帝位，载天子旗，往朝父瞽叟，夔夔唯谨，如子道。封弟象为诸侯。舜子商均亦不肖，舜乃豫荐禹于天。十七年而崩。三年丧毕，禹亦乃让舜子，如舜让尧子。诸侯归之，然后禹践天子位。尧子丹朱，舜子商均，皆有疆土，以奉先祀。服其服，礼乐如之。以客见天子，天子弗臣，示不敢专也。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
9cfe37ab-ea98-4ce4-a461-e8297b501ef0	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	28	自黄帝至舜、禹，皆同姓而异其国号，以章明德。故黄帝为有熊，帝颛顼为高阳，帝喾为高辛，帝尧为陶唐，帝舜为有虞。帝禹为夏后而别氏，姓姒氏。契为商，姓子氏。弃为周，姓姬氏。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
5795abd7-2bce-4297-800f-8a9fb531b120	ctext:shiji/wu-di-ben-ji	b824a426-1063-4d03-8276-4ca083ddbd4b	卷一	五帝本纪	29	太史公曰：学者多称五帝，尚矣。然尚书独载尧以来；而百家言黄帝，其文不雅驯，荐绅先生难言之。孔子所传宰予问五帝德及帝系姓，儒者或不传。余尝西至空桐，北过涿鹿，东渐于海，南浮江淮矣，至长老皆各往往称黄帝、尧、舜之处，风教固殊焉，总之不离古文者近是。予观春秋、国语，其发明五帝德、帝系姓章矣，顾弟弗深考，其所表见皆不虚。书缺有闲矣，其轶乃时时见于他说。非好学深思，心知其意，固难为浅见寡闻道也。余并论次，择其言尤雅者，故著为本纪书首。	\N	\N	\N	2026-04-18 02:26:34.101875+00	2026-04-18 02:26:34.101875+00	\N
28ec5ebc-71c9-4117-9b08-2d872bba1efe	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	1	夏禹，名曰文命。禹之父曰鲧，鲧之父曰帝颛顼，颛顼之父曰昌意，昌意之父曰黄帝。禹者，黄帝之玄孙而帝颛顼之孙也。禹之曾大父昌意及父鲧皆不得在帝位，为人臣。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
4df705a8-f625-4776-9277-5a5b7bfed69c	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	2	当帝尧之时，鸿水滔天，浩浩怀山襄陵，下民其忧。尧求能治水者，群臣四岳皆曰鲧可。尧曰："鲧为人负命毁族，不可。"四岳曰："等之未有贤于鲧者，愿帝试之。"于是尧听四岳，用鲧治水。九年而水不息，功用不成。于是帝尧乃求人，更得舜。舜登用，摄行天子之政，巡狩。行视鲧之治水无状，乃殛鲧于羽山以死。天下皆以舜之诛为是。于是舜举鲧子禹，而使续鲧之业。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
550e6c84-dbe8-4efe-95f6-6db86fb2c9a5	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	3	尧崩，帝舜问四岳曰："有能成美尧之事者使居官？"皆曰："伯禹为司空，可成美尧之功。"舜曰："嗟，然！"命禹："女平水土，维是勉之。"禹拜稽首，让于契、后稷、皋陶。舜曰："女其往视尔事矣。"	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
deed1a11-ccb2-4637-8162-7fa8e34f9d29	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	4	禹为人敏给克勤；其德不违，其仁可亲，其言可信；声为律，身为度，称以出；亹亹穆穆，为纲为纪。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
3ee21e62-8301-4635-9202-830d86e8eadd	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	5	禹乃遂与益、后稷奉帝命，命诸侯百姓兴人徒以傅土，行山表木，定高山大川。禹伤先人父鲧功之不成受诛，乃劳身焦思，居外十三年，过家门不敢入。薄衣食，致孝于鬼神。卑宫室，致费于沟淢。陆行乘车，水行乘船，泥行乘橇，山行乘檋。左准绳，右规矩，载四时，以开九州，通九道，陂九泽，度九山。令益予众庶稻，可种卑湿。命后稷予众庶难得之食。食少，调有馀相给，以均诸侯。禹乃行相地宜所有以贡，及山川之便利。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
d67ff3a8-1236-4189-b7e6-d5de7270d7c9	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	6	禹行自冀州始。冀州：既载壶口，治梁及岐。既修太原，至于岳阳。覃怀致功，至于衡漳。其土白壤。赋上上错，田中中，常、卫既从，大陆既为。鸟夷皮服。夹右碣石，入于海。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
ed7bbd9d-ebee-4ef6-bad9-19867dd15e7f	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	7	济、河维沇州：九河既道，雷夏既泽，雍、沮会同，桑土既蚕，于是民得下丘居土。其土黑坟，草繇木条。田中下，赋贞，作十有三年乃同。其贡漆丝，其篚织文。浮于济、漯，通于河。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
f571166e-c416-45e7-b691-1105315f7e27	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	8	海岱维青州：堣夷既略，潍、淄其道。其土白坟，海滨广舄，厥田斥卤。田上下，赋中上。厥贡盐絺，海物维错，岱畎丝、枲、铅、松、怪石，莱夷为牧，其篚酓丝。浮于汶，通于济。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
9e6e6585-aef6-4e7c-a404-db87de483095	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	9	海岱及淮维徐州：淮、沂其治，蒙、羽其艺。大野既都，东原底平。其土赤埴坟，草木渐包。其田上中，赋中中。贡维土五色，羽畎夏狄，峄阳孤桐，泗滨浮磬，淮夷蠙珠臮鱼，其篚玄纤缟。浮于淮、泗，通于河。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
f7d96969-19e9-4271-a521-145fcc64b151	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	10	淮海维扬州：彭蠡既都，阳鸟所居。三江既入，震泽致定。竹箭既布。其草惟夭，其木惟乔，其土涂泥。田下下，赋下上上杂。贡金三品，瑶、琨、竹箭，齿、革、羽、旄，岛夷卉服，其篚织贝，其包橘、柚锡贡。均江海，通淮、泗。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
4a96ef0f-dc10-4f2b-a1f2-a8c31684f988	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	11	荆及衡阳维荆州：江、汉朝宗于海。九江甚中，沱、涔已道，云土、梦为治。其土涂泥。田下中，赋上下。贡羽、旄、齿、革，金三品，杶、干、栝、柏，砺、砥、砮、丹，维箘簬、楛，三国致贡其名，包匦菁茅，其篚玄纁玑组，九江入赐大龟。浮于江、沱、涔、汉，逾于雒，至于南河。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
6e789d37-17b2-4e52-9f9d-f7eda67cbce3	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	12	荆河惟豫州：伊、雒、瀍、涧既入于河，荥播既都，道荷泽，被明都。其土壤，下土坟垆。田中上，赋杂上中。贡漆、丝、絺、紵，其篚纤絮，锡贡磬错。浮于雒，达于河。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
05caecd6-b625-4320-a1cf-6293ebe02924	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	13	华阳黑水惟梁州：汶、嶓既艺，沱、涔既道，蔡、蒙旅平，和夷砥绩。其土青骊。田下上，赋下中三错。贡璆、铁、银、镂、砮、磬，熊、罴、狐、狸、织皮。西倾因桓是来，浮于潜，逾于沔，入于渭，乱于河。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
e59e0390-ef53-4fb7-abab-b33338072552	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	14	黑水西河惟雍州：弱水既西，泾属渭汭。漆、沮既从，沣水所同。荆、岐已旅，终南、敦物至于鸟鼠。原隰砥绩，至于都野。三危既度，三苗大序。其土黄壤。田上上，赋中下。贡璆、琳、琅玕。浮于积石，至于龙门西河，会于渭汭。织皮昆仑、析支、渠搜，西戎即序。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
238de29d-785e-4924-8a5f-c70920b0707d	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	16	道九川：弱水至于合黎，馀波入于流沙。道黑水，至于三危，入于南海。道河积石，至于龙门，南至华阴，东至砥柱，又东至于盟津，东过雒汭，至于大邳，北过降水，至于大陆，北播为九河，同为逆河，入于海。嶓冢道瀁，东流为汉，又东为苍浪之水，过三澨，入于大别，南入于江，东汇泽为彭蠡，东为北江，入于海。汶山道江，东别为沱，又东至于醴，过九江，至于东陵，东迤北会于汇，东为中江，入于梅。道沇水，东为济，入于河，泆为荥，东出陶丘北，又东至于荷，又东北会于汶，又东北入于海。道淮自桐柏，东会于泗、沂，东入于海。道渭自鸟鼠同穴，东会于沣，又东北至于泾，东过漆、沮，入于河。道雒自熊耳，东北会于涧、瀍，又东会于伊，东北入于河。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
5587863f-1664-4cad-a8eb-d9b924fb8921	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	17	于是九州攸同，四奥既居，九山刊旅，九川涤原，九泽既陂，四海会同。六府甚修，众土交正，致慎财赋，咸则三壤成赋。中国赐土姓："祗台德先，不距朕行。"	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
8d6b45e9-b81d-4313-96ad-e176df3ee1ed	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	18	令天子之国以外五百里甸服：百里赋纳总，二百里纳銍，三百里纳秸服，四百里粟，五百里米。甸服外五百里侯服：百里采，二百里任国，三百里诸侯。侯服外五百里绥服：三百里揆文教，二百里奋武卫。绥服外五百里要服：三百里夷，二百里蔡。要服外五百里荒服：三百里蛮，二百里流。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
addd1f83-2e4a-49af-a1b9-3ad444fc6246	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	19	东渐于海，西被于流沙，朔、南暨：声教讫于四海。于是帝锡禹玄圭，以告成功于天下。天下于是太平治。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
0e1d63f6-ca1f-411f-9555-444ab2d6d52c	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	20	皋陶作士以理民。帝舜朝，禹、伯夷、皋陶相与语帝前。皋陶述其谋曰："信其道德，谋明辅和。"禹曰："然，如何？"皋陶曰："于！慎其身修，思长，敦序九族，众明高翼，近可远在已。"禹拜美言，曰："然。"皋陶曰："于！在知人，在安民。"禹曰："吁！皆若是，惟帝其难之。知人则智，能官人；能安民则惠，黎民怀之。能知能惠，何忧乎驩兜，何迁乎有苗，何畏乎巧言善色佞人？"皋陶曰："然，于！亦行有九德，亦言其有德。"乃言曰："始事事，宽而栗，柔而立，愿而共，治而敬，扰而毅，直而温，简而廉，刚而实，强而义，章其有常，吉哉。日宣三德，蚤夜翊明有家。日严振敬六德，亮采有国。翕受普施，九德咸事，俊乂在官，百吏肃谨。毋教邪淫奇谋。非其人居其官，是谓乱天事。天讨有罪，五刑五用哉。吾言砥可行乎？"禹曰："女言致可绩行。"皋陶曰："余未有知，思赞道哉。"	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
cfdbd31d-b860-4433-bfb1-631c655e8e7e	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	21	帝舜谓禹曰："女亦昌言。"禹拜曰；"于，予何言！予思日孳孳。"皋陶难禹曰："何谓孳孳？"禹曰："鸿水滔天，浩浩怀山襄陵，下民皆服于水。予陆行乘车，水行乘舟，泥行乘橇，山行乘檋，行山刊木。与益予众庶稻鲜食。以决九川致四海，浚畎浍致之川。与稷予众庶难得之食。食少，调有馀补不足，徙居。众民乃定，万国为治。"皋陶曰："然，此而美也。"	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
a86b73d4-51cd-4b43-9d30-31626997d738	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	22	禹曰："于，帝！慎乃在位，安尔止。辅德，天下大应。清意以昭待上帝命，天其重命用休。"帝曰："吁，臣哉，臣哉！臣作朕股肱耳目。予欲左右有民，女辅之。余欲观古人之象。日月星辰，作文绣服色，女明之。予欲闻六律五声八音，来始滑，以出入五言，女听。予即辟，女匡拂予。女无面谀。退而谤予。敬四辅臣。诸众谗嬖臣，君德诚施皆清矣。"禹曰："然。帝即不时，布同善恶则毋功。"	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
e3badf27-4684-4dc4-9860-319ca7d4a861	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	23	帝曰："毋若丹朱傲，维慢游是好，毋水行舟，朋淫于家，用绝其世。予不能顺是。"禹曰："予娶涂山，癸甲，生启予不子，以故能成水土功。辅成五服，至于五千里，州十二师，外薄四海，咸建五长，各道有功。苗顽不即功，帝其念哉。"帝曰："道吾德，乃女功序之也。"	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
b0e3d373-c55f-40cf-a4dc-3267e3dd4cad	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	24	皋陶于是敬禹之德，令民皆则禹。不如言，刑从之。舜德大明。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
193fd225-c320-4d70-9734-6bda98bae40d	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	25	于是夔行乐，祖考至，群后相让，鸟兽翔舞，箫韶九成，凤皇来仪，百兽率舞，百官信谐。帝用此作歌曰："陟天之命，维时维几。"乃歌曰："股肱喜哉，元首起哉，百工熙哉！"皋陶拜手稽首扬言曰："念哉，率为兴事，慎乃宪，敬哉！"乃更为歌曰："元首明哉，股肱良哉，庶事康哉！"又歌曰："元首丛脞哉，股肱惰哉，万事堕哉！"帝拜曰："然，往钦哉！"于是天下皆宗禹之明度数声乐，为山川神主。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
32280afb-415f-4d00-9ccf-82c54fee24b1	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	26	帝舜荐禹于天，为嗣。十七年而帝舜崩。三年丧毕，禹辞辟舜之子商均于阳城。天下诸侯皆去商均而朝禹。禹于是遂即天子位，南面朝天下，国号曰夏后，姓姒氏。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
020982a3-02fb-4484-a8c1-ea0f34debd35	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	27	帝禹立而举皋陶荐之，且授政焉，而皋陶卒。封皋陶之后于英、六，或在许。而后举益，任之政。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
3171b243-3240-4b62-a51d-393685f3b89f	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	28	十年，帝禹东巡狩，至于会稽而崩。以天下授益。三年之丧毕，益让帝禹之子启，而辟居箕山之阳。禹子启贤，天下属意焉。及禹崩，虽授益，益之佐禹日浅，天下未洽。故诸侯皆去益而朝启，曰："吾君帝禹之子也"。于是启遂即天子之位，是为夏后帝启。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
398cd6e7-6239-47ad-99e3-f70e46178d0c	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	29	夏后帝启，禹之子，其母涂山氏之女也。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
92f22c0b-fc8c-497c-88c5-a0c8f5c5e9d6	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	30	有扈氏不服，启伐之，大战于甘。将战，作甘誓，乃召六卿申之。启曰："嗟！六事之人，予誓告女：有扈氏威侮五行，怠弃三正，天用剿绝其命。今予维共行天之罚。左不攻于左，右不攻于右，女不共命。御非其马之政，女不共命。用命，赏于祖；不用命，僇于社，予则帑僇女。"遂灭有扈氏。天下咸朝。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
3c1435b1-e9ea-48ec-8849-14bdac168a5f	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	31	夏后帝启崩，子帝太康立。帝太康失国，昆弟五人，须于洛汭，作五子之歌。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
1cafb290-24c7-4901-8972-99282062a7fb	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	32	太康崩，弟中康立，是为帝中康。帝中康时，羲、和湎淫，废时乱日。胤往征之，作胤征。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
e7c4fce9-6945-4d28-b2aa-a6d5a47ca383	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	33	中康崩，子帝相立。帝相崩，子帝少康立。帝少康崩，子帝予立。帝予崩，子帝槐立。帝槐崩，子帝芒立。帝芒崩，子帝泄立。帝泄崩，子帝不降立。帝不降崩，弟帝扃立。帝扃崩，子帝廑立。帝廑崩，立帝不降之子孔甲，是为帝孔甲。帝孔甲立，好方鬼神，事淫乱。夏后氏德衰，诸侯畔之。天降龙二，有雌雄，孔甲不能食，未得豢龙氏。陶唐既衰，其后有刘累，学扰龙于豢龙氏，以事孔甲。孔甲赐之姓曰御龙氏，受豕韦之后。龙一雌死，以食夏后。夏后使求，惧而迁去。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
c5a04aff-290c-4f20-be17-921e3198d34b	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	34	孔甲崩，子帝皋立。帝皋崩，子帝发立。帝发崩，子帝履癸立，是为桀。帝桀之时，自孔甲以来而诸侯多畔夏，桀不务德而武伤百姓，百姓弗堪。乃召汤而囚之夏台，已而释之。汤修德，诸侯皆归汤，汤遂率兵以伐夏桀。桀走鸣条，遂放而死。桀谓人曰："吾悔不遂杀汤于夏台，使至此。"汤乃践天子位，代夏朝天下。汤封夏之后，至周封于杞也。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
03d3af12-9ed7-4b3e-9ffb-ec58d6be8264	ctext:shiji/xia-ben-ji	3fa76810-d788-484d-8452-f10cea1d9ad3	卷二	夏本纪	35	太史公曰：禹为姒姓，其后分封，用国为姓，故有夏后氏、有扈氏、有男氏、斟寻氏、彤城氏、褒氏、费氏、杞氏、缯氏、辛氏、冥氏、斟戈氏。孔子正夏时，学者多传夏小正云。自虞、夏时，贡赋备矣。或言禹会诸侯江南，计功而崩，因葬焉，命曰会稽。会稽者，会计也。	\N	\N	\N	2026-04-18 03:19:22.161432+00	2026-04-18 03:19:22.161432+00	\N
1305dabb-6001-4f14-9a1f-a067c22872bd	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	1	殷契，母曰简狄，有娀氏之女，为帝喾次妃。三人行浴，见玄鸟堕其卵，简狄取吞之，因孕生契。契长而佐禹治水有功。帝舜乃命契曰："百姓不亲，五品不训，汝为司徒而敬敷五教，五教在宽。"封于商，赐姓子氏。契兴于唐、虞、大禹之际，功业著于百姓，百姓以平。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
f8949ea6-e5dc-4d3d-b51d-7e55d57a055d	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	2	契卒，子昭明立。昭明卒，子相土立。相土卒，子昌若立。昌若卒，子曹圉立。曹圉卒，子冥立。冥卒，子振立。振卒，子微立。微卒，子报丁立。报丁卒，子报乙立。报乙卒，子报丙立。报丙卒，子主壬立。主壬卒，子主癸立。主癸卒，子天乙立，是为成汤。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
3add1fcb-6e9c-41ec-8703-c5b40cdd4fc3	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	3	成汤，自契至汤八迁。汤始居亳，从先王居，作帝诰。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
74657158-697a-4538-b5ab-61f27622b300	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	4	汤征诸侯。葛伯不祀，汤始伐之。汤曰："予有言：人视水见形，视民知治不。"伊尹曰："明哉！言能听，道乃进。君国子民，为善者皆在王官。勉哉，勉哉！"汤曰："汝不能敬命，予大罚殛之，无有攸赦。"作汤征。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
0b9130e9-850d-4f4f-983d-ea929d5e51f9	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	5	伊尹名阿衡。阿衡欲奸汤而无由，乃为有莘氏媵臣，负鼎俎，以滋味说汤，致于王道。或曰，伊尹处士，汤使人聘迎之，五反然后肯往从汤，言素王及九主之事。汤举任以国政。伊尹去汤适夏。既丑有夏，复归于亳。入自北门，遇女鸠、女房，作女鸠女房。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
929f85c6-4e1f-4d07-9ea8-3015237f3db4	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	6	汤出，见野张网四面，祝曰："自天下四方皆入吾网。"汤曰："嘻，尽之矣！"乃去其三面，祝曰："欲左，左。欲右，右。不用命，乃入吾网。"诸侯闻之，曰："汤德至矣，及禽兽。"	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
ded6f0dd-4d87-42c2-a3ab-9aa2c0618a2f	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	7	当是时，夏桀为虐政淫荒，而诸侯昆吾氏为乱。汤乃兴师率诸侯，伊尹从汤，汤自把钺以伐昆吾，遂伐桀。汤曰："格女众庶，来，女悉听朕言。匪台小子敢行举乱，有夏多罪，予维闻女众言，夏氏有罪。予畏上帝，不敢不正。今夏多罪，天命殛之。今女有众，女曰：'我君不恤我众，舍我啬事而割政'。女其曰：'有罪，其柰何'？夏王率止众力，率夺夏国。众有率怠不和，曰：'是日何时丧？予与女皆亡'！夏德若兹，今朕必往。尔尚及予一人致天之罚，予其大理女。女毋不信，朕不食言。女不从誓言，予则帑僇女，无有攸赦。"以告令师，作汤誓。于是汤曰："吾甚武"，号曰武王。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
e7ccfa3e-e0b1-437b-9cb4-e320b70b7dfb	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	8	桀败于有娀之虚，桀奔于鸣条，夏师败绩。汤遂伐三嵕，俘厥宝玉，义伯、仲伯作典宝。汤既胜夏，欲迁其社，不可，作夏社。伊尹报。于是诸侯毕服，汤乃践天子位，平定海内。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
a744030d-3de0-46c4-b87b-d73bc5b1e866	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	9	汤归至于泰卷陶，中垒作诰。既绌夏命，还亳，作汤诰："维三月，王自至于东郊。告诸侯群后：'毋不有功于民，勤力乃事。予乃大罚殛女，毋予怨。'曰：'古禹、皋陶久劳于外，其有功乎民，民乃有安。东为江，北为济，西为河，南为淮，四渎已修，万民乃有居。后稷降播，农殖百谷。三公咸有功于民，故后有立。昔蚩尤与其大夫作乱百姓，帝乃弗予，有状。先王言不可不勉。'曰：'不道，毋之在国，女毋我怨。'"以令诸侯。伊尹作咸有一德，咎单作明居。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
4b0e2b2a-3d54-411c-b93f-f331a8da5218	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	10	汤乃改正朔，易服色，上白，朝会以昼。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
bbe39025-88a3-4129-a89b-978ee110321e	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	11	汤崩，太子太丁未立而卒，于是乃立太丁之弟外丙，是为帝外丙。帝外丙即位三年，崩，立外丙之弟中壬，是为帝中壬。帝中壬即位四年，崩，伊尹乃立太丁之子太甲。太甲，成汤适长孙也，是为帝太甲。帝太甲元年，伊尹作伊训，作肆命，作徂后。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
a51bf2a4-ea14-4724-9e4f-ac1a87d0b871	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	12	帝太甲既立三年，不明，暴虐，不遵汤法，乱德，于是伊尹放之于桐宫。三年，伊尹摄行政当国，以朝诸侯。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
d24e32d6-026f-4df7-afc7-404cb9a03b87	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	13	帝太甲居桐宫三年，悔过自责，反善，于是伊尹乃迎帝太甲而授之政。帝太甲修德，诸侯咸归殷，百姓以宁。伊尹嘉之，乃作太甲训三篇，褒帝太甲，称太宗。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
b54957f2-5fe9-4681-83f4-9619d25f0542	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	14	太宗崩，子沃丁立。帝沃丁之时，伊尹卒。既葬伊尹于亳，咎单遂训伊尹事，作沃丁。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
9b63429e-37aa-4ade-b0fd-e80b2411456b	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	15	沃丁崩，弟太庚立，是为帝太庚。帝太庚崩，子帝小甲立。帝小甲崩，弟雍己立，是为帝雍己。殷道衰，诸侯或不至。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
0eef6842-052a-484e-9ea2-a25f8061a750	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	16	帝雍己崩，弟太戊立，是为帝太戊。帝太戊立伊陟为相。亳有祥桑谷共生于朝，一暮大拱。帝太戊惧，问伊陟。伊陟曰："臣闻妖不胜德，帝之政其有阙与？帝其修德。"太戊从之，而祥桑枯死而去。伊陟赞言于巫咸。巫咸治王家有成，作咸艾，作太戊。帝太戊赞伊陟于庙，言弗臣，伊陟让，作原命。殷复兴，诸侯归之，故称中宗。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
ff3af6c8-215a-41d3-942b-36afc15a5d6a	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	17	中宗崩，子帝中丁立。帝中丁迁于隞。河亶甲居相。祖乙迁于邢。帝中丁崩，弟外壬立，是为帝外壬。仲丁书阙不具。帝外壬崩，弟河亶甲立，是为帝河亶甲。河亶甲时，殷复衰。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
45c3095f-aed0-43ea-8199-3a8b13edac6c	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	18	河亶甲崩，子帝祖乙立。帝祖乙立，殷复兴。巫贤任职。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
0011d566-c78c-46b5-88ea-c1468b3b5f64	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	19	祖乙崩，子帝祖辛立。帝祖辛崩，弟沃甲立，是为帝沃甲。帝沃甲崩，立沃甲兄祖辛之子祖丁，是为帝祖丁。帝祖丁崩，立弟沃甲之子南庚，是为帝南庚。帝南庚崩，立帝祖丁之子阳甲，是为帝阳甲。帝阳甲之时，殷衰。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
4ff0a92f-ebe3-4139-a72b-59e3f6e475ff	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	20	自中丁以来，废适而更立诸弟子，弟子或争相代立，比九世乱，于是诸侯莫朝。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
1a03b780-b730-4744-978f-76ea8bc5f8ee	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	21	帝阳甲崩，弟盘庚立，是为帝盘庚。帝盘庚之时，殷已都河北，盘庚渡河南，复居成汤之故居，乃五迁，无定处。殷民咨胥皆怨，不欲徙。盘庚乃告谕诸侯大臣曰："昔高后成汤与尔之先祖俱定天下，法则可修。舍而弗勉，何以成德！"乃遂涉河南，治亳，行汤之政，然后百姓由宁，殷道复兴。诸侯来朝，以其遵成汤之德也。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
b5e063a0-1c5b-4773-80c5-9bd8afb1e05a	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	22	帝盘庚崩，弟小辛立，是为帝小辛。帝小辛立，殷复衰。百姓思盘庚，乃作盘庚三篇。帝小辛崩，弟小乙立，是为帝小乙。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
dbf046e5-e6e8-4fb5-81c7-3b9c6f0bb2b8	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	23	帝小乙崩，子帝武丁立。帝武丁即位，思复兴殷，而未得其佐。三年不言，政事决定于冢宰，以观国风。武丁夜梦得圣人，名曰说。以梦所见视群臣百吏，皆非也。于是乃使百工营求之野，得说于傅险中。是时说为胥靡，筑于傅险。见于武丁，武丁曰是也。得而与之语，果圣人，举以为相，殷国大治。故遂以傅险姓之，号曰傅说。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
336777c8-6430-44e7-bc27-e2ec5cb679c3	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	24	帝武丁祭成汤，明日，有飞雉登鼎耳而呴，武丁惧。祖己曰："王勿忧，先修政事。"祖己乃训王曰："唯天监下典厥义，降年有永有不永，非天夭民，中绝其命。民有不若德，不听罪，天既附命正厥德，乃曰其奈何。鸣呼！王嗣敬民，罔非天继，常祀毋礼于弃道。"武丁修政行德，天下咸驩，殷道复兴。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
42fa4233-08a9-4dfe-9390-a3dd18fb5cf1	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	25	帝武丁崩，子帝祖庚立。祖己嘉武丁之以祥雉为德，立其庙为高宗，遂作高宗肜日及训。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
c9fa4d85-aa1c-4701-a01b-de95100eae4f	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	26	帝祖庚崩，弟祖甲立，是为帝甲。帝甲淫乱，殷复衰。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
8892dd33-959c-4f94-a672-2d3881866f1d	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	27	帝甲崩，子帝廪辛立。帝廪辛崩，弟庚丁立，是为帝庚丁。帝庚丁崩，子帝武乙立。殷复去亳，徙河北。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
f99aae3a-64cc-4100-9e8a-31bb1ad598e8	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	28	帝武乙无道，为偶人，谓之天神。与之博，令人为行。天神不胜，乃僇辱之。为革囊，盛血，卬而射之，命曰"射天"。武乙猎于河渭之闲，暴雷，武乙震死。子帝太丁立。帝太丁崩，子帝乙立。帝乙立，殷益衰。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
7efb811b-f87a-4ee5-8b72-6b1c0fa01fd5	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	29	帝乙长子曰微子启，启母贱，不得嗣。少子辛，辛母正后，辛为嗣。帝乙崩，子辛立，是为帝辛，天下谓之纣。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
0e952322-5e5e-4fb6-a5f2-656ab94a04b5	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	30	帝纣资辨捷疾，闻见甚敏；材力过人，手格猛兽；知足以距谏，言足以饰非；矜人臣以能，高天下以声，以为皆出己之下。好酒淫乐，嬖于妇人。爱妲己，妲己之言是从。于是使师涓作新淫声，北里之舞，靡靡之乐。厚赋税以实鹿台之钱，而盈巨桥之粟。益收狗马奇物，充仞宫室。益广沙丘苑台，多取野兽蜚鸟置其中。慢于鬼神。大聚乐戏于沙丘，以酒为池，县肉为林，使男女裸相逐其闲，为长夜之饮。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
1d2b1727-3dfc-4d3c-ba72-18e8c664313b	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	31	百姓怨望而诸侯有畔者，于是纣乃重刑辟，有炮格之法。以西伯昌、九侯、鄂侯为三公。九侯有好女，入之纣。九侯女不喜淫，纣怒，杀之，而醢九侯。鄂侯争之强，辨之疾，并脯鄂侯。西伯昌闻之，窃叹。崇侯虎知之，以告纣，纣囚西伯羑里。西伯之臣闳夭之徒，求美女奇物善马以献纣，纣乃赦西伯。西伯出而献洛西之地，以请除炮格之刑。纣乃许之，赐弓矢斧钺，使得征伐，为西伯。而用费中为政。费中善谀，好利，殷人弗亲。纣又用恶来。恶来善毁谗，诸侯以此益疏。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
9c00f75a-4625-41ec-80e1-2e09392d5de2	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	32	西伯归，乃阴修德行善，诸侯多叛纣而往归西伯。西伯滋大，纣由是稍失权重。王子比干谏，弗听。商容贤者，百姓爱之，纣废之。及西伯伐饥国，灭之，纣之臣祖伊闻之而咎周，恐，奔告纣曰："天既讫我殷命，假人元龟，无敢知吉，非先王不相我后人，维王淫虐用自绝，故天弃我，不有安食，不虞知天性，不迪率典。今我民罔不欲丧，曰'天曷不降威，大命胡不至'？今王其柰何？"纣曰："我生不有命在天乎！"祖伊反，曰："纣不可谏矣。"西伯既卒，周武王之东伐，至盟津，诸侯叛殷会周者八百。诸侯皆曰："纣可伐矣。"武王曰："尔未知天命。"乃复归。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
92ba0a0d-53f3-4353-ae96-7503f5dd834b	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	13	帝曰：“畴若予工？”佥曰：“垂哉！”帝曰：“俞，咨！垂，汝共工。”垂拜稽首，让于殳斨暨伯与。”帝曰：“俞，往哉！汝谐。”	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
ef83a933-83b8-4fef-8964-96c41a3d5d84	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	33	纣愈淫乱不止。微子数谏不听，乃与大师、少师谋，遂去。比干曰："为人臣者，不得不以死争。"乃强谏纣。纣怒曰："吾闻圣人心有七窍。"剖比干，观其心。箕子惧，乃详狂为奴，纣又囚之。殷之大师、少师乃持其祭乐器奔周。周武王于是遂率诸侯伐纣。纣亦发兵距之牧野。甲子日，纣兵败。纣走入，登鹿台，衣其宝玉衣，赴火而死。周武王遂斩纣头，县之白旗。杀妲己。释箕子之囚，封比干之墓，表商容之闾。封纣子武庚、禄父，以续殷祀，令修行盘庚之政。殷民大说。于是周武王为天子。其后世贬帝号，号为王。而封殷后为诸侯，属周。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
640bc8f7-dd13-4e91-8df0-93ade83d247c	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	34	周武王崩，武庚与管叔、蔡叔作乱，成王命周公诛之，而立微子于宋，以续殷后焉。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
2696aac5-3f7a-4fd7-bb9d-0ab3fec95f52	ctext:shiji/yin-ben-ji	fc75773e-8545-4f24-8b9d-4bbd8db7dc9a	卷三	殷本纪	35	太史公曰：余以颂次契之事，自成汤以来，采于书诗。契为子姓，其后分封，以国为姓，有殷氏、来氏、宋氏、空桐氏、稚氏、北殷氏、目夷氏。孔子曰，殷路车为善，而色尚白。	\N	\N	\N	2026-04-18 03:21:59.716326+00	2026-04-18 03:21:59.716326+00	\N
3ecbede7-58e2-422e-9a97-b99eac729da1	ctext:shangshu/yao-dian	e0962711-a987-4411-885e-8e25388ff196	虞书	尧典	1	曰若稽古帝尧，曰放勋，钦、明、文、思、安安，允恭克让，光被四表，格于上下。克明俊德，以亲九族。九族既睦，平章百姓。百姓昭明，协和万邦。黎民于变时雍。	\N	\N	\N	2026-04-19 07:35:13.149383+00	2026-04-19 07:35:13.149383+00	\N
a2db8e80-9b9f-42a5-809f-9f997868c458	ctext:shangshu/yao-dian	e0962711-a987-4411-885e-8e25388ff196	虞书	尧典	2	乃命羲和，钦若昊天，历象日月星辰，敬授人时。分命羲仲，宅嵎夷，曰旸谷。寅宾出日，平秩东作。日中，星鸟，以殷仲春。厥民析，鸟兽孳尾。申命羲叔，宅南交。平秩南讹，敬致。日永，星火，以正仲夏。厥民因，鸟兽希革。分命和仲，宅西，曰昧谷。寅饯纳日，平秩西成。宵中，星虚，以殷仲秋。厥民夷，鸟兽毛毨。申命和叔，宅朔方，曰幽都。平在朔易。日短，星昴，以正仲冬。厥民隩，鸟兽氄毛。帝曰：“咨！汝羲暨和。朞三百有六旬有六日，以闰月定四时，成岁。允厘百工，庶绩咸熙。”	\N	\N	\N	2026-04-19 07:35:13.149383+00	2026-04-19 07:35:13.149383+00	\N
fe3cfb06-c9ad-47c3-9bb0-182c97b67fa8	ctext:shangshu/yao-dian	e0962711-a987-4411-885e-8e25388ff196	虞书	尧典	3	帝曰：“畴咨若时登庸？”放齐曰：“胤子朱启明。”帝曰：“吁！嚚讼可乎？”	\N	\N	\N	2026-04-19 07:35:13.149383+00	2026-04-19 07:35:13.149383+00	\N
46ffa2d7-bc6a-4405-8300-6baa1896be2f	ctext:shangshu/yao-dian	e0962711-a987-4411-885e-8e25388ff196	虞书	尧典	4	帝曰：“畴咨若予采？”驩兜曰：“都！共工方鸠僝功。”帝曰：“吁！静言庸违，象恭滔天。”	\N	\N	\N	2026-04-19 07:35:13.149383+00	2026-04-19 07:35:13.149383+00	\N
1d33833d-85dc-4bf8-beae-0963293bbc8f	ctext:shangshu/yao-dian	e0962711-a987-4411-885e-8e25388ff196	虞书	尧典	5	帝曰：“咨！四岳，汤汤洪水方割，荡荡怀山襄陵，浩浩滔天。下民其咨，有能俾乂？”佥曰：“于！鲧哉。”帝曰：“吁！咈哉，方命圮族。”岳曰：“异哉！试可乃已。”	\N	\N	\N	2026-04-19 07:35:13.149383+00	2026-04-19 07:35:13.149383+00	\N
3a22c9fb-c091-4d4f-9b07-7df5f2afa7e3	ctext:shangshu/yao-dian	e0962711-a987-4411-885e-8e25388ff196	虞书	尧典	6	帝曰，“往，钦哉！”九载，绩用弗成。	\N	\N	\N	2026-04-19 07:35:13.149383+00	2026-04-19 07:35:13.149383+00	\N
29a3bc2a-5433-4ce5-b0ed-b08efcf7aab0	ctext:shangshu/yao-dian	e0962711-a987-4411-885e-8e25388ff196	虞书	尧典	7	帝曰：“咨！四岳。朕在位七十载，汝能庸命，巽朕位？”岳曰：“否德忝帝位。”曰：“明明扬侧陋。”师锡帝曰：“有鳏在下，曰虞舜。”帝曰：“俞？予闻，如何？”岳曰：“瞽子，父顽，母嚚，象傲；克谐以孝，烝烝乂，不格奸。”帝曰：“我其试哉！女于时，观厥刑于二女。”厘降二女于妫汭，嫔于虞。帝曰：“钦哉！”	\N	\N	\N	2026-04-19 07:35:13.149383+00	2026-04-19 07:35:13.149383+00	\N
89ac5938-c7ac-4a10-a6e8-43e31459d6dd	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	1	曰若稽古帝舜，曰重华协于帝。浚哲文明，温恭允塞，玄德升闻，乃命以位。	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
75cbf644-b69e-45ec-9948-d5e696ec4c66	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	2	慎徽五典，五典克从；纳于百揆，百揆时叙；宾于四门，四门穆穆；纳于大麓，烈风雷雨弗迷。帝曰：“格！汝舜。询事考言，乃言砥可绩，三载。汝陟帝位。”舜让于德，弗嗣。正月上日，受终于文祖。	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
17ae63dc-1d98-4bb8-8cc6-212624546dec	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	3	在璇玑玉衡，以齐七政。肆类于上帝，禋于六宗，望于山川，徧于群神。辑五瑞。既月乃日，觐四岳群牧，班瑞于群后。	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
c3772f82-8847-456e-9cd6-9e799bff9e8d	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	4	岁二月，东巡守，至于岱宗，柴。望秩于山川，肆觐东后。协时月正日，同律度量衡。修五礼、五玉、三帛、二生、一死贽。如五器，卒乃复。五月南巡守，至于南岳，如岱礼。八月西巡守，至于西岳，如初。十有一月朔巡守，至于北岳，如西礼。归，格于艺祖，用特。五载一巡守，群后四朝。敷奏以言，明试以功，车服以庸。	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
c61e9958-7e77-4d6f-9536-4ae5356c8ea2	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	5	肇十有二州，封十有二山，浚川。	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
e8c96231-b0b1-4a33-b6c3-01a019a408b9	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	6	象以典刑，流宥五刑，鞭作官刑，扑作教刑，金作赎刑。眚灾肆赦，怙终贼刑。钦哉，钦哉，惟刑之恤哉！流共工于幽洲，放驩兜于崇山，窜三苗于三危，殛鲧于羽山，四罪而天下咸服。	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
655fe902-39e2-4f2c-9f8e-db21c6627337	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	7	二十有八载，帝乃殂落。百姓如丧考妣，三载，四海遏密八音。	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
3a70d789-a1fe-4aa0-966d-f0b52af27144	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	8	月正元日，舜格于文祖，询于四岳，辟四门，明四目，达四聪。“咨，十有二牧！”曰，“食哉惟时！柔远能迩，敦德允元，而难任人，蛮夷率服。”	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
3e036732-b51d-497e-ad54-4d59ef72e38e	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	9	舜曰：“咨，四岳！有能奋庸熙帝之载，使宅百揆亮采，惠畴？”佥曰：“伯禹作司空。”帝曰：“俞，咨！禹，汝平水土，惟时懋哉！”禹拜稽首，让于稷、契暨皋陶。帝曰：“俞，汝往哉！”	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
0e739221-dba5-44fa-9531-807439367dfa	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	10	帝曰：“弃，黎民阻饥，汝后稷，播时百谷。”	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
91840d96-a3b2-46e6-9fb4-549ef59d9a00	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	11	帝曰：“契，百姓不亲，五品不逊。汝作司徒，敬敷五教，在宽。”	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
8f8d21ff-b9b2-4a37-94bf-623f925c8876	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	12	帝曰：“皋陶，蛮夷猾夏，寇贼奸宄。汝作士，五刑有服，五服三就。五流有宅，五宅三居。惟明克允！”	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
7467c089-f4e9-4cb2-9bdc-56d5b3fca499	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	14	帝曰：“畴若予上下草木鸟兽？”佥曰：“益哉！”帝曰：“俞，咨！益，汝作朕虞。”益拜稽首，让于朱虎、熊罴。帝曰：“俞，往哉！汝谐。”	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
b1f19b2d-9ec5-46f2-927c-8f4078be86e0	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	15	帝曰：“咨！四岳，有能典朕三礼？”佥曰：“伯夷！”帝曰：“俞，咨！伯，汝作秩宗。夙夜惟寅，直哉惟清。”伯拜稽首，让于夔、龙。帝曰：“俞，往，钦哉！”	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
4a861ae0-e28a-436b-9e65-426884c86e3e	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	16	帝曰：“夔！命汝典乐，教胄子，直而温，宽而栗，刚而无虐，简而无傲。诗言志，歌永言，声依永，律和声。八音克谐，无相夺伦，神人以和。”夔曰：“于！予击石拊石，百兽率舞。”	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
cd733c3c-8e21-4b24-9c50-4fc941e64439	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	17	帝曰：“龙，朕堲谗说殄行，震惊朕师。命汝作纳言，夙夜出纳朕命，惟允！”	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
5d13df64-6bf4-49fe-9e78-1556e7dd66ee	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	18	帝曰：“咨！汝二十有二人，钦哉！惟时亮天功。”	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
3cb2bd6a-b365-4a0b-b783-1cb02813db2f	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	19	三载考绩，三考，黜陟幽明，庶绩咸熙。分北三苗。	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
018fcd98-5296-463b-9fdf-7e15060fdcc8	ctext:shangshu/shun-dian	4a3951d2-fae8-4e30-a04d-4fb9f6454402	虞书	舜典	20	舜生三十徵庸，三十在位。五十载，陟方乃死。	\N	\N	\N	2026-04-19 07:35:13.227099+00	2026-04-19 07:35:13.227099+00	\N
6b101aa0-36ad-4983-99b5-3131ad5c7058	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	1	周后稷，名弃。其母有邰氏女，曰姜原。姜原为帝喾元妃。姜原出野，见巨人迹，心忻然说，欲践之，践之而身动如孕者。居期而生子，以为不祥，弃之隘巷，马牛过者皆辟不践；徙置之林中，适会山林多人，迁之；而弃渠中冰上，飞鸟以其翼覆荐之。姜原以为神，遂收养长之。初欲弃之，因名曰弃。	\N	\N	\N	2026-04-19 23:32:48.267255+00	2026-04-19 23:32:48.267255+00	\N
60754d74-d39a-43d8-a23c-9f61edbc465b	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	2	弃为儿时，屹如巨人之志。其游戏，好种树麻、菽，麻、菽美。及为成人，遂好耕农，相地之宜，宜谷者稼穑焉，民皆法则之。帝尧闻之，举弃为农师，天下得其利，有功。帝舜曰：“弃，黎民始饥，尔后稷播时百谷。”封弃于邰，号曰后稷，别姓姬氏。后稷之兴，在陶唐﹑虞﹑夏之际，皆有令德。	\N	\N	\N	2026-04-19 23:32:48.267255+00	2026-04-19 23:32:48.267255+00	\N
c6b3e894-12e0-4d54-bb3c-c3565285c79b	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	3	后稷卒，子不窋立。不窋末年，夏后氏政衰，去稷不务，不窋以失其官而犇戎狄之间。不窋卒，子鞠立。鞠卒，子公刘立。公刘虽在戎狄之间，复修后稷之业，务耕种，行地宜，自漆、沮度渭，取材用，行者有资，居者有畜积，民赖其庆。百姓怀之，多徙而保归焉。周道之兴自此始，故诗人歌乐思其德。公刘卒，子庆节立，国于豳。	\N	\N	\N	2026-04-19 23:32:48.267255+00	2026-04-19 23:32:48.267255+00	\N
0e3170b4-a877-4b60-a3f6-7981138006aa	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	4	庆节卒，子皇仆立。皇仆卒，子差弗立。差弗卒，子毁隃立。毁隃卒，子公非立。公非卒，子高圉立。高圉卒，子亚圉立。亚圉卒，子公叔祖类立。公叔祖类卒，子古公亶父立。古公亶父复修后稷、公刘之业，积德行义，国人皆戴之。薰育戎狄攻之，欲得财物，予之。已复攻，欲得地与民。民皆怒，欲战。古公曰：“有民立君，将以利之。今戎狄所为攻战，以吾地与民。民之在我，与其在彼，何异。民欲以我故战，杀人父子而君之，予不忍为。”乃与私属遂去豳，度漆、沮，逾梁山，止于岐下。豳人举国扶老携弱，尽复归古公于岐下。及他旁国闻古公仁，亦多归之。于是古公乃贬戎狄之俗，而营筑城郭室屋，而邑别居之。作五官有司。民皆歌乐之，颂其德。	\N	\N	\N	2026-04-19 23:32:48.267255+00	2026-04-19 23:32:48.267255+00	\N
0548af11-c886-4b4f-9139-51c5fe41ebf4	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	5	古公有长子曰太伯，次曰虞仲。太姜生少子季历，季历娶太任，皆贤妇人，生昌，有圣瑞。古公曰：“我世当有兴者，其在昌乎？”长子太伯、虞仲知古公欲立季历以传昌，乃二人亡如荆蛮，文身断髪，以让季历。	\N	\N	\N	2026-04-19 23:32:48.267255+00	2026-04-19 23:32:48.267255+00	\N
20115cec-2bdc-49b4-86f5-dd12202f7bc3	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	6	古公卒，季历立，是为公季。公季修古公遗道，笃于行义，诸侯顺之。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
0c7e196b-7f50-42ee-9c99-ae3802272ccc	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	7	公季卒，子昌立，是为西伯。西伯曰文王，遵后稷、公刘之业，则古公、公季之法，笃仁，敬老，慈少。礼下贤者，日中不暇食以待士，士以此多归之。伯夷、叔齐在孤竹，闻西伯善养老，盍往归之。太颠、闳夭、散宜生、鬻子、辛甲大夫之徒皆往归之。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
e08af469-9cd6-4827-9531-90242afddbe6	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	8	崇侯虎谮西伯于殷纣曰：“西伯积善累德，诸侯皆向之，将不利于帝。”帝纣乃囚西伯于羑里。闳夭之徒患之。乃求有莘氏美女，骊戎之文马，有熊九驷，他奇怪物，因殷嬖臣费仲而献之纣。纣大说，曰：“此一物足以释西伯，况其多乎！”乃赦西伯，赐之弓矢斧钺，使西伯得征伐。曰：“谮西伯者，崇侯虎也。”西伯乃献洛西之地，以请纣去炮格之刑。纣许之。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
ba48ac76-ac01-4e2c-9de7-8c29cc72549c	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	9	西伯阴行善，诸侯皆来决平。于是虞、芮之人有狱不能决，乃如周。入界，耕者皆让畔，民俗皆让长。虞、芮之人未见西伯，皆惭，相谓曰：“吾所争，周人所耻，何往为，秖取辱耳。”遂还，俱让而去。诸侯闻之，曰“西伯盖受命之君”。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
a9f90b6d-070a-44f0-bfa2-9b6073debc0c	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	10	明年，伐犬戎。明年，伐密须。明年，败耆国。殷之祖伊闻之，惧，以告帝纣。纣曰：“不有天命乎？是何能为！”明年，伐邘。明年，伐崇侯虎。而作丰邑，自岐下而徙都丰。明年，西伯崩，太子发立，是为武王。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
f3b17d1e-69ea-4100-8a2d-77b7e7b74326	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	11	西伯盖即位五十年。其囚羑里，盖益易之八卦为六十四卦。诗人道西伯，盖受命之年称王而断虞芮之讼。后十年而崩，谥为文王。改法度，制正朔矣。追尊古公为太王，公季为王季：盖王瑞自太王兴。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
44e7ed91-a875-4c2e-b3b9-67cd29bd997f	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	12	武王即位，太公望为师，周公旦为辅，召公、毕公之徒左右王，师修文王绪业。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
18762cf6-ccd2-4109-9052-0b3257622490	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	34	宣王不修籍于千亩，虢文公谏曰不可，王弗听。三十九年，战于千亩，王师败绩于姜氏之戎。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
3c8787b0-033a-472b-b1f1-cb2d095072be	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	13	九年，武王上祭于毕。东观兵，至于盟津。为文王木主，载以车，中军。武王自称太子发，言奉文王以伐，不敢自专。乃告司马、司徒、司空、诸节：“齐栗，信哉！予无知，以先祖有德臣，小子受先功，毕立赏罚，以定其功。”遂兴师。师尚父号曰：“总尔众庶，与尔舟楫，后至者斩。”武王渡河，中流，白鱼跃入王舟中，武王俯取以祭。既渡，有火自上复于下，至于王屋，流为乌，其色赤，其声魄云。是时，诸侯不期而会盟津者八百诸侯。诸侯皆曰：“纣可伐矣。”武王曰：“女未知天命，未可也。”乃还师归。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
b5c3dd7e-bdaf-4ff1-8414-38dbea5d56a2	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	14	居二年，闻纣昏乱暴虐滋甚，杀王子比干，囚箕子。太师疵、少师强抱其乐器而奔周。于是武王遍告诸侯曰：“殷有重罪，不可以不毕伐。”乃遵文王，遂率戎车三百乘，虎贲三千人，甲士四万五千人，以东伐纣。十一年十二月戊午，师毕渡盟津，诸侯咸会。曰：“孳孳无怠！”武王乃作太誓，告于众庶：“今殷王纣乃用其妇人之言，自绝于天，毁坏其三正，离逖其王父母弟，乃断弃其先祖之乐，乃为淫声，用变乱正声，怡说妇人。故今予发维共行天罚。勉哉夫子，不可再，不可三！”	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
330009fe-958b-4596-be84-adf2ba52e844	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	15	二月甲子昧爽，武王朝至于商郊牧野，乃誓。武王左杖黄钺，右秉白旄，以麾。曰：“远矣西土之人！”武王曰：“嗟！我有国冢君，司徒、司马、司空，亚旅、师氏，千夫长、百夫长，及庸、蜀、羌、髳、微、纑、彭、濮人，称尔戈，比尔干，立尔矛，予其誓。”王曰：“古人有言‘牝鸡无晨。牝鸡之晨，惟家之索’。今殷王纣维妇人言是用，自弃其先祖肆祀不答，昏弃其家国，遗其王父母弟不用，乃维四方之多罪逋逃是崇是长，是信是使，俾暴虐于百姓，以奸轨于商国。今予发维共行天之罚。今日之事，不过六步七步，乃止齐焉，夫子勉哉！不过于四伐五伐六伐七伐，乃止齐焉，勉哉夫子！尚桓桓，如虎如罴，如豺如离，于商郊，不御克奔，以役西土，勉哉夫子！尔所不勉，其于尔身有戮。”誓已，诸侯兵会者车四千乘，陈师牧野。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
a4b2e644-1b2c-4d1f-9f1f-ffe5eced65d8	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	16	帝纣闻武王来，亦发兵七十万人距武王。武王使师尚父与百夫致师，以大卒驰帝纣师。纣师虽众，皆无战之心，心欲武王亟入。纣师皆倒兵以战，以开武王。武王驰之，纣兵皆崩畔纣。纣走，反入登于鹿台之上，蒙衣其殊玉，自燔于火而死。武王持大白旗以麾诸侯，诸侯毕拜武王，武王乃揖诸侯，诸侯毕从。武王至商国，商国百姓咸待于郊。于是武王使群臣告语商百姓曰：“上天降休！”商人皆再拜稽首，武王亦答拜。遂入，至纣死所。武王自射之，三发而后下车，以轻剑击之，以黄钺斩纣头，县大白之旗。已而至纣之嬖妾二女，二女皆经自杀。武王又射三发，击以剑，斩以玄钺，县其头小白之旗。武王已乃出复军。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
e435258b-ed6f-421d-bbf9-a71d7db53d75	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	17	其明日，除道，修社及商纣宫。及期，百夫荷罕旗以先驱。武王弟叔振铎奉陈常车，周公旦把大钺，毕公把小钺，以夹武王。散宜生、太颠、闳夭皆执剑以卫武王。既入，立于社南大卒之左，［左］右毕从。毛叔郑奉明水，卫康叔封布兹，召公奭赞采，师尚父牵牲。尹佚厕祝曰：“殷之末孙季纣，殄废先王明德，侮蔑神祇不祀，昏暴商邑百姓，其章显闻于天皇上帝。”于是武王再拜稽首，曰：“膺更大命，革殷，受天明命。”武王又再拜稽首，乃出。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
004d1907-81d1-4efc-accc-d97f5db1187f	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	18	封商纣子禄父殷之馀民。武王为殷初定未集，乃使其弟管叔鲜、蔡叔度相禄父治殷。已而命召公释箕子之囚。命毕公释百姓之囚，表商容之闾。命南宫括散鹿台之财，发钜桥之粟，以振贫弱萌隶。命南宫括、史佚展九鼎保玉。命闳夭封比干之墓。命宗祝享祠于军。乃罢兵西归。行狩，记政事，作武成。封诸侯，班赐宗彝，作分殷之器物。武王追思先圣王，乃褒封神农之后于焦，黄帝之后于祝，帝尧之后于蓟，帝舜之后于陈，大禹之后于杞。于是封功臣谋士，而师尚父为首封。封尚父于营丘，曰齐。封弟周公旦于曲阜，曰鲁。封召公奭于燕。封弟叔鲜于管，弟叔度于蔡。馀各以次受封。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
736a84c5-3b83-4e37-b05f-38533f53f29f	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	19	武王徵九牧之君，登豳之阜，以望商邑。武王至于周，自夜不寐。周公旦即王所，曰：“曷为不寐？”王曰：“告女：维天不飨殷，自发未生于今六十年，麋鹿在牧，蜚鸿满野。天不享殷，乃今有成。维天建殷，其登名民三百六十夫，不显亦不宾灭，以至今。我未定天保，何暇寐！”王曰：“定天保，依天室，悉求夫恶，贬从殷王受。日夜劳来定我西土，我维显服，及德方明。自洛汭延于伊汭，居易毋固，其有夏之居。我南望三涂，北望岳鄙，顾詹有河，粤詹雒、伊，毋远天室。”营周居于雒邑而后去。纵马于华山之阳，放牛于桃林之虚；偃干戈，振兵释旅：示天下不复用也。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
31997e5d-401f-4dd7-b525-2c851b79b62d	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	20	武王已克殷，后二年，问箕子殷所以亡。箕子不忍言殷恶，以存亡国宜告。武王亦丑，故问以天道。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
a005deaa-f9b5-4036-9a0c-92a7e6c8dfb7	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	21	武王病。天下未集，群公惧，穆卜，周公乃祓斋，自为质，欲代武王，武王有瘳。后而崩，太子诵代立，是为成王。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
a794c502-7bc0-4808-b65f-58eae708b057	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	22	成王少，周初定天下，周公恐诸侯畔周，公乃摄行政当国。管叔、蔡叔群弟疑周公，与武庚作乱，畔周。周公奉成王命，伐诛武庚、管叔，放蔡叔。以微子开代殷后，国于宋。颇收殷馀民，以封武王少弟封为卫康叔。晋唐叔得嘉谷，献之成王，成王以归周公于兵所。周公受禾东土，鲁天子之命。初，管、蔡畔周，周公讨之，三年而毕定，故初作大诰，次作微子之命，次归禾，次嘉禾，次康诰、酒诰、梓材，其事在周公之篇。周公行政七年，成王长，周公反政成王，北面就群臣之位。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
9a9f420b-4d39-49fd-92b9-232a169d4513	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	32	厉王太子静匿召公之家，国人闻之，乃围之。召公曰：“昔吾骤谏王，王不从，以及此难也。今杀王太子，王其以我为雠而怼怒乎？夫事君者，险而不雠怼，怨而不怒，况事王乎！”乃以其子代王太子，太子竟得脱。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
bd48691a-e5ec-41e7-9fe4-0053aff9f9b0	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	23	成王在丰，使召公复营洛邑，如武王之意。周公复卜申视，卒营筑，居九鼎焉。曰：“此天下之中，四方入贡道里均。”作召诰、洛诰。成王既迁殷遗民，周公以王命告，作多士、无佚。召公为保，周公为师，东伐淮夷，残奄，迁其君薄泵。成王自奄归，在宗周，作多方。既绌殷命，袭淮夷，归在丰，作周官。兴正礼乐，度制于是改，而民和睦，颂声兴。成王既伐东夷，息慎来贺，王赐荣伯作贿息慎之命。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
5f5325c1-6652-4d98-b8d6-c1c055ac6d98	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	24	成王将崩，惧太子钊之不任，乃命召公、毕公率诸侯以相太子而立之。成王既崩，二公率诸侯，以太子钊见于先王庙，申告以文王、武王之所以为王业之不易，务在节俭，毋多欲，以笃信临之，作顾命。太子钊遂立，是为康王。康王即位，遍告诸侯，宣告以文武之业以申之，作《康诰》。故成康之际，天下安宁，刑错四十馀年不用。康王命作策毕公分居里，成周郊，作《毕命》。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
717cca04-a728-49fe-9aab-bb72919c6bf7	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	25	康王卒，子昭王瑕立。昭王之时，王道微缺。昭王南巡狩不返，卒于江上。其卒不赴告，讳之也。立昭王子满，是为穆王。穆王即位，春秋已五十矣。王道衰微，穆王闵文武之道缺，乃命伯臩申诫太仆国之政，作臩命。复宁。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
ac5d8604-30fe-4efe-b1b5-35d39bbd1cbe	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	26	穆王将征犬戎，祭公谋父谏曰：“不可。先王耀德不观兵。夫兵戢而时动，动则威，观则玩，玩则无震。是故周文公之颂曰：‘载戢干戈，载櫜弓矢，我求懿德，肆于时夏，允王保之。’先王之于民也，茂正其德而厚其性，阜其财求而利其器用，明利害之乡，以文修之，使之务利而辟害，怀德而畏威，故能保世以滋大。昔我先王世后稷以服事虞、夏。及夏之衰也，弃稷不务，我先王不窋用失其官，而自窜于戎狄之闲。不敢怠业，时序其德，遵修其绪，修其训典，朝夕恪勤，守以敦笃，奉以忠信。奕世载德，不忝前人。至于文王、武王，昭前之光明而加之以慈和，事神保民，无不欣喜。商王帝辛大恶于民，庶民不忍，欣载武王，以致戎于商牧。是故先王非务武也，劝恤民隐而除其害也。夫先王之制，邦内甸服，邦外侯服，侯卫宾服，夷蛮要服，戎翟荒服。甸服者祭，侯服者祀，宾服者享，要服者贡，荒服者王。日祭，月祀，时享，岁贡，终王。先王之顺祀也，有不祭则修意，有不祀则修言，有不享则修文，有不贡则修名，有不王则修德，序成而有不至则修刑。于是有刑不祭，伐不祀，征不享，让不贡，告不王。于是有刑罚之辟，有攻伐之兵，有征讨之备，有威让之命，有文告之辞。布令陈辞而有不至，则增修于德，无勤民于远。是以近无不听，远无不服。今自大毕、伯士之终也，犬戎氏以其职来王，天子曰‘予必以不享征之，且观之兵’，无乃废先王之训，而王几顿乎？吾闻犬戎树敦，率旧德而守终纯固，其有以御我矣。”王遂征之，得四白狼四白鹿以归。自是荒服者不至。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
b5814fda-b773-4132-ab91-a88c46509493	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	27	诸侯有不睦者，甫侯言于王，作修刑辟。王曰：“吁，来！有国有土，告汝祥刑。在今尔安百姓，何择非其人，何敬非其刑，何居非其宜与？两造具备，师听五辞。五辞简信，正于五刑。五刑不简，正于五罚。五罚不服，正于五过。五过之疵，官狱内狱，阅实其罪，惟钧其过。五刑之疑有赦，五罚之疑有赦，其审克之。简信有众，惟讯有稽。无简不疑，共严天威。黥辟疑赦，其罚百率，阅实其罪。劓辟疑赦，其罚倍洒，阅实其罪。膑辟疑赦，其罚倍差，阅实其罪。宫辟疑赦，其罚五百率，阅实其罪。大辟疑赦，其罚千率，阅实其罪。墨罚之属千，劓罚之属千，膑罚之属五百，宫罚之属三百，大辟之罚其属二百：五刑之属三千。”命曰甫刑。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
fdc41fbe-b66c-4527-9098-7692b48fc761	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	28	穆王立五十五年，崩，子共王繄扈立。共王游于泾上，密康公从，有三女奔之。其母曰：“必致之王。夫兽三为群，人三为众，女三为粲。王田不取群，公行不下众，王御不参一族。夫粲，美之物也。众以美物归女，而何德以堪之？王犹不堪，况尔之小丑乎！小丑备物，终必亡。”康公不献，一年，共王灭密。共王崩，子懿王艰立。懿王之时，王室遂衰，诗人作刺。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
873ad554-007c-4d91-82e0-b1685d3a5291	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	29	懿王崩，共王弟辟方立，是为孝王。孝王崩，诸侯复立懿王太子燮，是为夷王。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
e2559eb6-c01b-4a41-8d38-08ffc6e0f4a6	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	30	夷王崩，子厉王胡立。厉王即位三十年，好利，近荣夷公。大夫芮良夫谏厉王曰：“王室其将卑乎？夫荣公好专利而不知大难。夫利，百物之所生也，天地之所载也，而有专之，其害多矣。天地百物皆将取焉，何可专也？所怒甚多，不备大难。以是教王，王其能久乎？夫王人者，将导利而布之上下者也。使神人百物无不得极，犹日怵惕惧怨之来也。故《颂》曰‘思文后稷，克配彼天，立我蒸民，莫匪尔极’。大雅曰‘陈锡载周’。是不布利而惧难乎，故能载周以至于今。今王学专利，其可乎？匹夫专利，犹谓之盗，王而行之，其归鲜矣。荣公若用，周必败也。”厉王不听，卒以荣公为卿士，用事。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
0e23a98a-e828-4000-a766-82b7e80c9d0b	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	31	王行暴虐侈傲，国人谤王。召公谏曰：“民不堪命矣。”王怒，得卫巫，使监谤者，以告则杀之。其谤鲜矣，诸侯不朝。三十四年，王益严，国人莫敢言，道路以目。厉王喜，告召公曰：“吾能弭谤矣，乃不敢言。”召公曰：“是鄣之也。防民之口，甚于防水。水壅而溃，伤人必多，民亦如之。是故为水者决之使导，为民者宣之使言。故天子听政，使公卿至于列士献诗，瞽献曲，史献书，师箴，瞍赋，蒙诵，百工谏，庶人传语，近臣尽规，亲戚补察，瞽史教诲，耆艾修之，而后王斟酌焉，是以事行而不悖。民之有口也，犹土之有山川也，财用于是乎出：犹其有原隰衍沃也，衣食于是乎生。口之宣言也，善败于是乎兴。行善而备败，所以产财用衣食者也。夫民虑之于心而宣之于口，成而行之。若壅其口，其与能几何？”王不听。于是国莫敢出言，三年，乃相与畔，袭厉王。厉王出奔于彘。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
ab09f32a-953c-4782-b648-b9feeac0d31a	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	33	召公、周公二相行政，号曰“共和”。共和十四年，厉王死于彘。太子静长于召公家，二相乃共立之为王，是为宣王。宣王即位，二相辅之，修政，法文、武、成、康之遗风，诸侯复宗周。十二年，鲁武公来朝。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
30dbd59d-0302-48ea-832d-cc1f376d46c0	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	35	宣王既亡南国之师，乃料民于太原。仲山甫谏曰：“民不可料也。”宣王不听，卒料民。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
bf40b376-c07a-4b1c-86ab-bad39a52ece9	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	36	四十六年，宣王崩，子幽王宫湦立。幽王二年，西周三川皆震。伯阳甫曰：“周将亡矣。夫天地之气，不失其序；若过其序，民乱之也。阳伏而不能出，阴迫而不能蒸，于是有地震。今三川实震，是阳失其所而填阴也。阳失而在阴，原必塞；原塞，国必亡。夫水土演而民用也。土无所演，民乏财用，不亡何待！昔伊、洛竭而夏亡，河竭而商亡。今周德若二代之季矣，其川原又塞，塞必竭。夫国必依山川，山崩川竭，亡国之徵也。川竭必山崩。若国亡不过十年，数之纪也。天之所弃，不过其纪。”是岁也，三川竭，岐山崩。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
7042eef4-870e-4c21-9c29-499aa3252c73	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	37	三年，幽王嬖爱褒姒。褒姒生子伯服，幽王欲废太子。太子母申侯女，而为后。后幽王得褒姒，爱之，欲废申后，并去太子宜臼，以褒姒为后，以伯服为太子。周太史伯阳读史记曰：“周亡矣。”昔自夏后氏之衰也，有二神龙止于夏帝庭而言曰：“余，褒之二君。”夏帝卜杀之与去之与止之，莫吉。卜请其漦而藏之，乃吉。于是布币而策告之，龙亡而漦在，椟而去之。夏亡，传此器殷。殷亡，又传此器周。比三代，莫敢发之，至厉王之末，发而观之。漦流于庭，不可除。厉王使妇人裸而噪之。漦化为玄鼋，以入王后宫。后宫之童妾既龀而遭之，既笄而孕，无夫而生子，惧而弃之。宣王之时童女谣曰：“厌弧箕服，实亡周国。”于是宣王闻之，有夫妇卖是器者，宣王使执而戮之。逃于道，而见乡者后宫童妾所弃妖子出于路者，闻其夜啼，哀而收之，夫妇遂亡，奔于褒。褒人有罪，请入童妾所弃女子者于王以赎罪。弃女子出于褒，是为褒姒。当幽王三年，王之后宫见而爱之，生子伯服，竟废申后及太子，以褒姒为后，伯服为太子。太史伯阳曰：“祸成矣，无可奈何！”	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
c219deda-2e78-43f0-bb72-17776a40d5ed	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	38	褒姒不好笑，幽王欲其笑万方，故不笑。幽王为烽燧大鼓，有寇至则举烽火。诸侯悉至，至而无寇，褒姒乃大笑。幽王说之，为数举烽火。其后不信，诸侯益亦不至。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
550409b2-d1e0-4c90-8e36-d90b58e31d1e	ctext:shiji/zhou-ben-ji	07ec7d8a-b32c-4f35-bb1e-b0c14ad03998	卷四	周本纪	39	幽王以虢石父为卿，用事，国人皆怨。石父为人佞巧善谀好利，王用之。又废申后，去太子也。申侯怒，与缯、西夷犬戎攻幽王。幽王举烽火徵兵，兵莫至。遂杀幽王骊山下，虏褒姒，尽取周赂而去。于是诸侯乃即申侯而共立故幽王太子宜臼，是为平王，以奉周祀。	\N	\N	\N	2026-04-19 23:49:20.480067+00	2026-04-19 23:49:20.480067+00	\N
