    place_id uuid NOT NULL,
    name text NOT NULL,
    dynasty text,
    year_start integer,
    year_end integer,
    geometry_variant public.geometry(Geometry,4326),
    source_evidence_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: places; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.places (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    slug text NOT NULL,
    ancient_name text,
    modern_name jsonb,
    geometry public.geometry(Geometry,4326),
    fuzziness real DEFAULT 0,
    modern_country text DEFAULT 'CN'::text,
    reality_status public.reality_status DEFAULT 'historical'::public.reality_status NOT NULL,
    provenance_tier public.provenance_tier DEFAULT 'primary_text'::public.provenance_tier NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    deleted_at timestamp with time zone
);


--
-- Name: polities; Type: TABLE; Schema: public; Owner: -
