    resolve_rule jsonb NOT NULL
);


--
-- Name: seed_mappings; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.seed_mappings (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    dictionary_entry_id uuid NOT NULL,
    target_entity_type text NOT NULL,
    target_entity_id uuid NOT NULL,
    confidence numeric(3,2),
    mapping_method text NOT NULL,
    mapping_created_at timestamp with time zone DEFAULT now() NOT NULL,
    mapping_status text DEFAULT 'active'::text NOT NULL,
    notes jsonb,
    CONSTRAINT seed_mappings_confidence_check CHECK (((confidence >= 0.00) AND (confidence <= 1.00))),
    CONSTRAINT seed_mappings_mapping_status_check CHECK ((mapping_status = ANY (ARRAY['active'::text, 'superseded'::text, 'rejected'::text, 'pending_review'::text])))
);


--
-- Name: COLUMN seed_mappings.mapping_status; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.seed_mappings.mapping_status IS 'Lifecycle status: pending_review (multi-hit awaiting manual triage) / active (bound as authoritative seed) / superseded (replaced by newer mapping) / rejected (explicitly rejected by reviewer).';


--
-- Name: source_evidences; Type: TABLE; Schema: public; Owner: -
